import React from 'react';
import { Box, Text } from 'ink';
import { useApi } from '../hooks/use-api.js';
import { PatternList } from '../components/pattern-list.js';
import type { Pattern } from '../components/pattern-list.js';

export interface PatternsScreenProps {
  endpoint: string;
  apiKey: string;
}

export function PatternsScreen({ endpoint, apiKey }: PatternsScreenProps) {
  const { data, loading, error } = useApi<Pattern[]>(
    endpoint, '/api/v1/patterns', apiKey,
  );

  if (loading) return <Text>Loading patterns...</Text>;
  if (error) return <Text color="red">Error: {error}</Text>;

  return (
    <Box flexDirection="column">
      <Text bold underline>Pattern Analysis</Text>
      <Box marginTop={1}>
        <PatternList patterns={data || []} limit={25} />
      </Box>
    </Box>
  );
}
